    def _normalize_selected_paths(raw) -> List[str]:
        if isinstance(raw, str):
            raw = [raw]
        if not isinstance(raw, list):
            return []

        cleaned: List[str] = []
        for item in raw:
            if not isinstance(item, str):
                continue
            text = item.strip()
            if not text:
                continue
            cleaned.append(_canonicalize_faiss_path(text))

        # Deduplicate preserving order
        seen: set[str] = set()
        deduped: List[str] = []
        for path in cleaned:
            if path in seen:
                continue
            seen.add(path)
            deduped.append(path)
        return deduped

    def _find_faiss_store_node_key(start_node_key: str, node_map_payload: Dict[str, Any]) -> str | None:
        if not start_node_key or start_node_key not in node_map_payload:
            return None
        queue: deque[str] = deque([start_node_key])
        visited: set[str] = {start_node_key}
        while queue:
            current = queue.popleft()
            node = node_map_payload.get(current)
            if not isinstance(node, dict):
                continue
            if node.get("type") == "FaissStore":
                return current
            for inp in node.get("inputs", []) or []:
                if not isinstance(inp, str):
                    continue
                if inp in visited:
                    continue
                if inp not in node_map_payload:
                    continue
                visited.add(inp)
                queue.append(inp)
        return None

